import { useEffect, useState } from 'react';

const NAV_LINKS = ['About', 'Skills', 'Projects', 'Experience', 'Contact'];

export default function Navbar({ activeSection, setActiveSection }) {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav
      style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
        height: '64px', display: 'flex', alignItems: 'center',
        justifyContent: 'space-between', padding: '0 2rem',
        background: 'rgba(8,12,20,0.8)',
        backdropFilter: 'blur(12px)',
        borderBottom: '1px solid var(--border)',
        transition: 'all 0.3s ease',
      }}
    >
      {/* Logo */}
      <a
        href="#about"
        onClick={(e) => { e.preventDefault(); setActiveSection('about'); }}
        style={{ fontFamily: 'Syne', fontWeight: 800, fontSize: '1.2rem', letterSpacing: '-0.03em' }}
      >
        <span style={{ color: 'var(--accent)' }}>S</span>anjay
        <span style={{ color: 'var(--accent)' }}>.S</span>
      </a>

      {/* Links */}
      <div style={{ display: 'flex', gap: '2rem' }}>
        {NAV_LINKS.map((link) => {
          const isSelected = activeSection.toLowerCase() === link.toLowerCase();
          return (
            <a
              key={link}
              href={`#${link.toLowerCase()}`}
              onClick={(e) => {
                e.preventDefault();
                setActiveSection(link.toLowerCase());
              }}
              style={{
                fontSize: '0.82rem', fontWeight: 500, letterSpacing: '0.06em',
                textTransform: 'uppercase',
                color: isSelected ? 'var(--accent)' : 'var(--muted)',
                transition: 'all 0.2s',
                position: 'relative',
                paddingBottom: '4px'
              }}
              onMouseEnter={(e) => (e.target.style.color = 'var(--text)')}
              onMouseLeave={(e) => (e.target.style.color = isSelected ? 'var(--accent)' : 'var(--muted)')}
            >
              {link}
              {isSelected && (
                <span style={{
                  position: 'absolute', bottom: 0, left: 0, right: 0, height: '2px',
                  background: 'var(--accent)', borderRadius: '2px',
                  animation: 'slideIn 0.3s ease-out'
                }} />
              )}
            </a>
          );
        })}
      </div>

      <style>{`
        @keyframes slideIn {
          from { transform: scaleX(0); }
          to { transform: scaleX(1); }
        }
      `}</style>
    </nav>
  );
}
